{
  "query": "query Movies($filter: MovieFilterInput) {
  movies(filter: $filter) {
    data {
      id
      title
      description
      releaseYear
      posterUrl
      isActive
      genres { id name }
      directors { id firstName lastName }
    }
    total
    page
    limit
  }
}",
  "variables": {
    "filter": {
      "page": 1,
      "limit": 10
    }
  }
}

{
  "query": "query Movie($id: ID!) {
  movie(id: $id) {
    id
    title
    description
    releaseYear
    posterUrl
    isActive
    genres { id name }
    actors { id firstName lastName photoUrl }
    directors { id firstName lastName photoUrl }
    reviews {
      id
      text
      rating
      createdAt
      user { firstName lastName }
    }
  }
}",
  "variables": {
    "id": "{{movieId}}"
  }
}

{
  "query": "query Genres {
  genres {
    id
    name
  }
}",
  "variables": {}
}

{
  "query": "query Actors($filter: QueryActorInput) {\n  actors(filter: $filter) {\n    data { id firstName lastName photoUrl }\n    total page limit\n  }\n}",
  "variables": {
    "filter": {
      "page": 1,
      "limit": 20
    }
  }
}

{
  "query": "query Directors {
  directors {
    data { id firstName lastName photoUrl }
    total
  }
}",
  "variables": {}
}

{
  "query": "query MoviesAdmin($filter: MovieFilterInput) {
  moviesAdmin(filter: $filter) {
    data {
      id
      title
      isActive
      releaseYear
      genres { name }
    }
    total page limit
  }
}",
  "variables": {
    "filter": {
      "page": 1,
      "limit": 20
    }
  }
}

{
  "query": "mutation CreateMovie($input: CreateMovieInput!) {\n  createMovie(input: $input) {\n    id\n    title\n    releaseYear\n    isActive\n    genres { id name }\n  }\n}",
  "variables": {
    "input": {
      "title": "GraphQL Test Movie",
      "description": "Фільм створений через GraphQL мутацію для демонстрації.",
      "releaseYear": 2024,
      "genreIds": [],
      "actorIds": [],
      "directorIds": []
    }
  }
}

{
  "query": "mutation UpdateMovie($id: ID!, $input: UpdateMovieInput!) {\n  updateMovie(id: $id, input: $input) {\n    id\n    title\n    releaseYear\n    isActive\n  }\n}",
  "variables": {
    "id": "{{movieId}}",
    "input": {
      "title": "Updated via GraphQL Mutation",
      "releaseYear": 2025
    }
  }
}

{
  "query": "mutation DeactivateMovie($id: ID!) {
  deactivateMovie(id: $id) {
    id
    title
    isActive
  }
}",
  "variables": {
    "id": "{{movieId}}"
  }
}

{
  "query": "mutation ActivateMovie($id: ID!) {
  activateMovie(id: $id) {
    id
    title
    isActive
  }
}",
  "variables": {
    "id": "{{movieId}}"
  }
}

{
  "query": "mutation DeleteMovie($id: ID!) {\n  deleteMovie(id: $id)\n}",
  "variables": {
    "id": "{{movieId}}"
  }
}

{
  "query": "mutation CreateReview($input: CreateReviewInput!) {\n  createReview(input: $input) {\n    id\n    text\n    rating\n    createdAt\n    user { firstName lastName }\n  }\n}",
  "variables": {
    "input": {
      "movieId": "{{movieId}}",
      "text": "Надзвичайний фільм! GraphQL review.",
      "rating": 5
    }
  }
}

{
  "query": "mutation DeleteReview($id: ID!) {\n  deleteReview(id: $id)\n}",
  "variables": {
    "id": "{{reviewId}}"
  }
}

{
  "query": "mutation CreateGenre($input: CreateGenreInput!) {\n  createGenre(input: $input) {\n    id\n    name\n  }\n}",
  "variables": {
    "input": {
      "name": "GQL Test Genre"
    }
  }
}
